import{_ as t,o as a,c as o,a6 as i,gU as s,gV as g,gW as n,gX as e,gY as l,gZ as m,ey as c,g_ as _,gL as d,g$ as h,h0 as k,kf as b,kg as f,kh as j,ki as u,kj as x,ii as w,kk as P,kl as $,km as v,jc as C,jd as A,je as D,kn as S,jf as K,jg as T,ko as V,kp as F,fw as E,jD as H,jE as W,jF as y,fY as B,jG as R,jH as I,jI as L,jJ as M,jK as N,jL as q,jM as z,jO as G,jP as J,iG as r,jQ as O,jR as U,jS as Y,jT as Z,jU as Q,jh as X,ji as pp,kq as sp,jj as rp,jk as tp,kr as ap,ks as op,kt as ip,ku as gp,jv as np,jw as ep,jx as lp,jy as mp,jz as cp,jA as _p,iE as dp,iF as hp,iH as kp,jB as bp,jC as fp,iM as jp,gx as up,kv as xp}from"./chunks/framework.UYVGz2W_.js";const Kp=JSON.parse('{"title":"ステータス、公開、レビュー","description":"","frontmatter":{},"headers":[],"relativePath":"ja/status-publish-review/index.md","filePath":"ja/status-publish-review/index.md"}'),wp={name:"ja/status-publish-review/index.md"};function Pp($p,p,vp,Cp,Ap,Dp){return a(),o("div",null,[...p[0]||(p[0]=[i('<h1 id="ステータス、公開、レビュー" tabindex="-1">ステータス、公開、レビュー <a class="header-anchor" href="#ステータス、公開、レビュー" aria-label="Permalink to “ステータス、公開、レビュー”">​</a></h1><h2 id="コンセプトの公開" tabindex="-1">コンセプトの公開 <a class="header-anchor" href="#コンセプトの公開" aria-label="Permalink to “コンセプトの公開”">​</a></h2><p><strong>コンセプト</strong>を公開するには、ナビゲーションメニューから<strong>コンセプト</strong>ページに移動します。</p><p><img src="'+s+'" alt="コンセプトメニュー"></p><p>コンセプトをアップロードするには、<strong>コンセプトへの新しい参照を追加</strong>ボタンをクリックします。</p><p>1つまたは複数のコンセプトを同時にアップロードできます。</p><p><img src="'+g+'" alt="コンセプトの空ページ"></p><p>プレビューをアップロードすると、コンセプトページは次のようになります。</p><p><img src="'+n+'" alt="コンセプトの入力ページ"></p><p>コンセプトとやりとりするには2つの方法があります。画像をクリックして拡大表示します。 もう1つは、ステータス部分をクリックして右側の<strong>コメントパネル</strong>を開く方法です。</p><p>コメントパネルでは、コンセプトを既存のアセットにリンクするか、コンセプトを削除するかの2つのオプションがあります。 また、アセットのステータスを変更してコメントを追加することもできます。</p><p><strong>コンセプト</strong>ごとに1つのバージョンを持つことが基本です。承認されていない場合は、同じコンセプトの複数のバージョンを作成しないよう、新しいコンセプトをアップロードする必要があります。</p><p>1つのコンセプトは1つのタスクです。</p><p><img src="'+e+'" alt="コンセプトオプション"></p><h2 id="コンセプトとアセットのリンク" tabindex="-1">コンセプトとアセットのリンク <a class="header-anchor" href="#コンセプトとアセットのリンク" aria-label="Permalink to “コンセプトとアセットのリンク”">​</a></h2><p>コンセプトをアップロードすると、アセットにリンクすることができます。</p><p>アセットのステータス部分にリンクが表示されます。</p><p>コンセプトのステータス部分をクリックすると、右側にコメントパネルが開きます。</p><p><img src="'+l+'" alt="コンセプトコメントパネル"></p><p>コメントパネルの上部には、2つのオプションがあります。コンセプトをアセットにリンクするか、コンセプトを削除します。</p><p>アセットをリンクするには、[リンク] ボタン <img src="'+m+'" alt="リンクボタン"> をクリックします。</p><p>Kitsu は、アップロードしたコンセプトにリンク可能なすべての <strong>アセット</strong> を表示します。</p><p>コメントパネルの上部には、リンクされたアセットがリスト表示されます。現時点では、<strong>リンクなし</strong> です。</p><p><img src="'+c+'" alt="コンセプトのリンク"></p><p>アセットをリンクするには、それをクリックする必要があります。画面の上部とコンセプトのプレビューの下にリンクされたアセットの名前が表示されます。</p><p><img src="'+_+'" alt="コンセプトのアセットのリンク"></p><p>コンセプトがアセットにリンクされると、アセットの詳細ページでコンセプトを確認できるようになります。</p><p>アセットページに戻り、コンセプトを確認したいアセット名をクリックします。</p><p><img src="'+d+'" alt="アセット詳細ページ"></p><p>デフォルトでは、キャスティングの詳細が画面の2番目の部分に表示されます。 ドロップダウンメニューを使用してコンセプトを選択します。</p><p><img src="'+h+'" alt="アセット詳細コンセプト"></p><p>コンセプトセクションに入ると、このアセット用に作成されたすべてのコンセプトが表示されます。ステータス別にフィルタリングすることもできます。</p><p><img src="'+k+'" alt="アセット詳細コンセプトリスト"></p><h2 id="ステータスの変更とコメントの追加" tabindex="-1">ステータスの変更とコメントの追加 <a class="header-anchor" href="#ステータスの変更とコメントの追加" aria-label="Permalink to “ステータスの変更とコメントの追加”">​</a></h2><p>タスクのステータスを変更したりコメントを追加するには、 タスクのステータスをクリックする必要があります。</p><p><img src="'+b+'" alt="ショットのステータス"></p><p>右側にパネルが表示され、ここでコメントの追加、ステータスの変更、ファイルの添付を行うことができます。</p><p><img src="'+f+'" alt="コメントパネル"></p><p>コメントパネル**は2つのタブに分かれています。</p><ul><li>コメントを投稿</li><li>リビジョンを公開</li></ul><p><strong>ステータス</strong>を変更するには、<strong>コメントを投稿</strong>タブに留まります。</p><p>コメントには <strong>Markdown</strong> 言語を使用します。特定の構文が必要な場合は、markdown guide ウェブサイトをご覧ください： <a href="https://www.markdownguide.org/basic-syntax/" target="_blank" rel="noreferrer">https://www.markdownguide.org/basic-syntax/</a></p><p><strong>コメントを残す</strong> セクションでは、コメントを投稿する際にチーム内の誰かを <strong>タグ付け</strong> することができます。 <code>@</code> を入力すると、チームのリストを含むサブメニューが開きます。</p><p><img src="'+j+'" alt="誰かをタグ付け"></p><p>また、「@」と部署名を入力することで、部署全体に<strong>タグ付け</strong>することもできます。</p><p><img src="'+u+'" alt="部署にタグ付け"></p><p>コメントに<strong>チェックリスト</strong>を追加することができます。</p><p>「<strong>チェックリストを追加</strong>」ボタンをクリックすると、チェックリストの最初の項目が表示されます。</p><p><img src="'+x+'" alt="チェックリストの追加"></p><p>コメントを入力し、<strong>Enter</strong>キーを押してチェックリストに別の行を追加するか、<strong>チェックリストの追加</strong>ボタンを再度クリックします。</p><p><img src="'+w+'" alt="チェックリスト"></p><p>コメントの他に、画像としてファイルを添付することもできます。 <strong>添付ファイルを追加</strong> ボタンをクリックします。</p><p><img src="'+P+'" alt="添付ファイルの追加（シンプル）"></p><p><strong>ハードドライブからファイルを選択</strong>するか、<strong>スクリーンショット</strong>をここに貼り付けます。</p><p><img src="'+$+'" alt="添付ファイルのスナップショット"></p><p><strong>ファイルを添付</strong>をクリックして添付ファイルを検証します。</p><p>次に、ドロップダウンメニューから必要な<strong>ステータス</strong>を選択します。</p><p><img src="'+v+'" alt="ステータスリスト"></p><p>次に、<strong>投稿</strong>ボタンをクリックして世界に投稿します。</p><h2 id="プレビューをバージョンとして公開する" tabindex="-1">プレビューをバージョンとして公開する <a class="header-anchor" href="#プレビューをバージョンとして公開する" aria-label="Permalink to “プレビューをバージョンとして公開する”">​</a></h2><p>プレビュー、画像、動画を公開するには、タスクのコメントパネルで<strong>「リビジョンを公開」</strong>タブを選択します。</p><p>WFA<strong>ステータスのように、</strong>「フィードバックリクエスト」<strong>オプション付きのステータスを使用すると、Kitsuは自動的に</strong>「リビジョンを公開」**タブに切り替わります。</p><p><img src="'+C+'" alt="リビジョンを公開"></p><p>任意のコメントに1つまたは複数のプレビューを追加できます。 画像（<code>.png</code>、<code>.jpg</code>、<code>.jpeg</code>、<code>.gif</code>）、ビデオ（<code>.mp4</code>、<code>.mov</code>、<code>.wmv</code>）、 または<code>.glb</code>ファイルを追加できます。 ブラウザからすべてのプレビューを確認したり、すべてを混ぜ合わせたりできます。</p><p>.glb<code> ファイルについては、ワイヤーフレームとして確認することもできます。また、</code>.HDR` ファイルを追加して照明を確認することもできます。</p><p>しかし、<code>.pdf</code>、<code>.zip</code>、<code>.rar</code>、<code>.ma</code>、<code>.mb</code>などのファイルは ダウンロードして確認する必要があります。</p><p>次に、<strong>[プレビューリビジョンを追加して公開]</strong>ボタンをクリックします。エクスプローラーが開き、ファイルまたは複数のファイルを選択できるようになります。</p><p><img src="'+A+'" alt="添付プレビュー"></p><p>この画面に<strong>スクリーンショットをコピー＆ペースト</strong>することもできます。</p><p>添付ファイルのプレビューが表示されます。</p><p><img src="'+D+'" alt="添付プレビュー入力済み"></p><p>ファイルを選択すると、<strong>添付プレビュー</strong>ボタンの近くにファイル名が表示されます。</p><p><img src="'+S+'" alt="添付プレビューの確認"></p><p>コメントセクションにファイルを<strong>ドラッグ＆ドロップ</strong>することもできます。</p><p><img src="'+K+'" alt="添付プレビューのドラッグ＆ドロップ"></p><p>プレビューの上に<strong>コメント</strong>を追加することができます。</p><p>コメントを残す**ボタンをクリックして、コメントセクションを開きます。</p><p><img src="'+T+'" alt="公開にコメントを追加する"></p><p>投稿**ボタンをクリックして、ステータスを選択し、プレビューを公開します。</p><h2 id="サムネイルの追加" tabindex="-1">サムネイルの追加 <a class="header-anchor" href="#サムネイルの追加" aria-label="Permalink to “サムネイルの追加”">​</a></h2><p>プレビューをサムネイルとして定義するには、プレビューがリビジョンとしてアップロードされている必要があります。</p><p>プレビュー、画像、または動画を公開するには、タスクのコメントパネルで<strong>[リビジョンを公開]</strong>タブを選択します。</p><p>プレビューをアセットまたはショットタスクの<strong>サムネイルとして使用</strong>できます。 これにより、メインページでアセット/ショットを認識しやすくなります。 リストページで希望するステータスをクリックし、右パネルで<strong>プレビュー</strong>ボタンをクリックします（1）。</p><p><img src="'+V+'" alt="サムネイルボタン"></p><p>ボタンをクリックすると、最初のフレームまたは任意のフレームを選択できます。フレームを選択すると、サムネイルが表示され、ボタンがグレーに変わります。</p><p><img src="'+F+'" alt="サムネイル適用"></p><h2 id="レビューの実行" tabindex="-1">レビューの実行 <a class="header-anchor" href="#レビューの実行" aria-label="Permalink to “レビューの実行”">​</a></h2><p>アーティストが<strong>レビュー</strong>を必要とする場合、タスクの状態も変更します <img src="'+E+'" alt="wfa">。</p><p>ステータスをクリックすると右パネルが開き、レビューを開始できます。</p><p>右パネルからバージョンを閲覧したり、パネルのサイドをつかんで拡大したり、フルスクリーンにすることもできます <img src="'+H+'" alt="フルスクリーン">。</p><p><img src="'+W+'" alt="グローバルページでのレビュー"></p><p>3Dファイル（<code>.glb</code>ファイル）については、ワイヤーフレームとしてレビューすることもできます。また、<code>.HDR</code>ファイルを追加して照明を確認することもできます。</p><p>3Dファイルは、カーソルでドラッグして移動したり、スクロールでズームイン/ズームアウトしたりすることができます。</p><p><img src="'+y+'" alt="3Dワイヤーフレームのレビュー"></p><p><img src="'+B+'" alt="背景プレビューの例"></p><p><strong>鉛筆</strong>ツールを使用してプレビュー上に直接描画し、色を選択することができます！<a href="../img/getting-started/draw.png">鉛筆</a>。</p><p><img src="'+R+'" alt="レビュー描画"></p><p>また、フレーム上に<strong>テキスト</strong>を追加することもできます。</p><p><img src="'+I+'" alt="レビュー描画テキスト"></p><p>コメントなしでプレビューを表示したい場合は、<strong>注釈を隠す</strong>ために、<strong>万年筆</strong>ボタンをクリックします。 <img src="'+L+'" alt="注釈を隠す"></p><p>どのバージョンでも）フレームにタグを付けるには、<code>@</code>を入力すると、チームリストを含むサブメニューが開き、<strong>フレーム</strong>の入力を開始できます。</p><p><img src="'+M+'" alt="フレームにタグを付ける"></p><p>また、<strong>スクリーンショットを添付</strong>して各フレームの描画をエクスポートすることもできます。</p><p>添付を追加**]ボタンをクリックします。</p><p><img src="'+N+'" alt="添付"></p><p>添付オプションで<strong>注釈のスナップショットを添付</strong>することもできます。</p><p><img src="'+q+'" alt="添付のスナップショット"></p><p>ボタンをクリックすると、Kitsuが注釈付きのすべてのフレームを取得し、結果を表示します。 <strong>確認</strong>をクリックすると、それらを公開できます。</p><p><img src="'+z+'" alt="添付のスナップショット詳細"></p><p>線を削除したい場合は、<strong>鉛筆</strong>アイコンをもう一度クリックすると、カーソルが多方向クロスに変わります！<a href="../img/getting-started/direction_arrow.png">鉛筆</a> その後、線を移動して選択することができます。</p><p><img src="'+G+'" alt="レビュー描画"></p><p>方向を示す十字のアイコンでラインを選択し、削除アイコンを押します。 <img src="'+J+'" alt="ラインの削除"></p><p>フルスクリーン<strong>に切り替えると、</strong>比較**ボタンをクリックすると、2つのタスクタイプまたはバージョンを並べて比較することができます <img src="'+r+'" alt="比較ボタン">。</p><p><img src="'+O+'" alt="比較ボタン"></p><p>そこから、ステータスを変更することもできます！<a href="../img/getting-started/retake_icon.png">再提出</a>をクリックすると、アーティストに変更を依頼できます。</p><p>または、<img src="'+U+'" alt="完了">に変更して、アーティストに作業が承認されたことを通知することもできます。</p><h2 id="コンセプトの確認" tabindex="-1">コンセプトの確認 <a class="header-anchor" href="#コンセプトの確認" aria-label="Permalink to “コンセプトの確認”">​</a></h2><p>アーティストがコンセプトをアップロードしたら、スーパーバイザーまたはディレクターが確認することができます。</p><p>コンセプトを確認するには、画面上部のナビゲーションメニューを使用してコンセプトページを選択します。</p><p><img src="'+s+'" alt="メニューコンセプト"></p><p>アップロードされたすべてのコンセプト、ステータス、割り当て、リンクされたアセットを確認できます。</p><p><img src="'+Y+'" alt="Ccncept filled status"></p><p>コンセプトを確認するには、ステータスの部分をクリックしてコメントパネルを開きます。コメントパネルを拡大したり、フルスクリーン表示にしたりすることができます。</p><p>次に、コメントを入力し、ステータスとして<strong>承認済み</strong>または<strong>却下済み</strong>を選択し、<strong>投稿</strong>ボタンで確定します。</p><p><img src="'+Z+'" alt="Ccncept status comment"></p><p><strong>ステータス</strong>フィルターでページをフィルタリングして、<strong>ニュートラル</strong>ステータスのコンセプトをすべて表示することができます。</p><p><img src="'+Q+'" alt="Ccnceptステータスフィルター"></p><p>また、アーティストごとにフィルタリングしたり、並び順を変更することもできます。</p><h2 id="複数のプレビューを1つのバージョンとして追加" tabindex="-1">複数のプレビューを1つのバージョンとして追加 <a class="header-anchor" href="#複数のプレビューを1つのバージョンとして追加" aria-label="Permalink to “複数のプレビューを1つのバージョンとして追加”">​</a></h2><p>複数の画像を同時に追加したり、画像を1つアップロードした後に別の画像を追加することができます。</p><p><img src="'+X+'" alt="プレビューのドラッグ＆ドロップによる添付"></p><p><strong>プレビューの追加</strong>ポップアップでは、ファイルの選択を求められます。</p><p>アップロードした画像を閲覧できます。</p><p>番号をクリックしてドラッグ＆ドロップすると、プレビューの順序を変更できます。</p><p><img src="'+pp+'" alt="プレビューのドラッグ＆ドロップによる添付"></p><p>プレビューを削除するには、コメントパネルをドラッグしてバージョン番号をクリックして拡大する必要があります。</p><p><img src="'+sp+'" alt="enlarge comment section"></p><p>そして、<img src="'+rp+'" alt="delete button">をクリックします。</p><p><img src="'+tp+'" alt="enlarge comment section delete"></p><h2 id="バッチごとのステータス変更" tabindex="-1">バッチごとのステータス変更 <a class="header-anchor" href="#バッチごとのステータス変更" aria-label="Permalink to “バッチごとのステータス変更”">​</a></h2><p>あるいは、<strong>バッチ</strong>ごとに変更することもできます。</p><p><strong>Ctrl</strong> または <strong>Shift</strong> キーを押すことで、複数のショットまたはアセットを選択することができます。</p><p>次に、アクションメニューの<strong>ステータス変更</strong>セクションに進みます。</p><p><img src="'+ap+'" alt="アクションメニューのステータス"></p><p>選択したタスクの新しいステータスを選択します (1)。 選択したすべてのタスクにコメントを追加することもできます (2) 新しいステータスを <strong>Confirm</strong> ボタンで確定します。</p><p><img src="'+op+'" alt="バッチごとのステータスの変更"><img src="'+ip+'" alt="メタデータカラムのソート順"></p><p>ショットは名前ではなく、メタデータ列の情報によってソートされます。</p><p><img src="'+gp+'" alt="メタデータ列ソート結果"></p><p>メタデータ列の名前や情報を編集したり、削除したりしたい場合は、メニューから選択することもできます。</p><p>また、<strong>CSVインポート</strong>を使用して、カスタムメタデータ列を素早く埋めることもできます。 まず、<strong>メタデータ列</strong>をKitsuに作成し、スプレッドシートに追加し、データを<strong>CSVインポート</strong>にコピー＆ペーストします。</p><p>CSVインポートでショット情報を更新</p><h1 id="プレイリスト" tabindex="-1">プレイリスト <a class="header-anchor" href="#プレイリスト" aria-label="Permalink to “プレイリスト”">​</a></h1><h2 id="プレイリストを作成する" tabindex="-1">プレイリストを作成する <a class="header-anchor" href="#プレイリストを作成する" aria-label="Permalink to “プレイリストを作成する”">​</a></h2><p>ドロップダウンメニューに<strong>プレイリスト</strong>ページがあります。</p><p><img src="'+np+'" alt="プレイリストメインメニュー"></p><p><strong>プレイリスト</strong>ページは2つの部分に分かれています。</p><p>(1) プレイリストを作成したり、既存のプレイリストを読み込むことができるプレイリストリスト。 (2) 最後に作成したプレイリストと最後に変更したプレイリスト</p><p><img src="'+ep+'" alt="プレイリストページ"></p><p>まず、<strong>プレイリスト</strong>を作成します <img src="'+lp+'" alt="プレイリスト追加ボタン">。デフォルトの名前は デフォルト名は日付と時間です。すぐに変更できます。プレイリストを スタジオまたはクライアントと共有するか、また、ショットまたはアセットのプレイリストにするかを選択できます。 プレイリストにタスクタイプのタグを追加することもできます。</p><p><img src="'+mp+'" alt="プレイリスト追加ページ"></p><p>プレイリストを作成したら、検索/フィルタバーを使用して、プレイリストに追加するショットを選択できます。</p><p>また、<strong>ムービー全体を追加</strong>することもでき、ムービー内のすべてのショットが追加されます。</p><p><strong>デイリー保留中</strong>を選択すると、その日の<strong>WFA</strong>タスクがすべて追加されます。</p><p>特定のシーケンスのみに焦点を当てたい場合は、<strong>シーケンス全体を追加</strong>することもできます。</p><p>グローバルショット/アセットページと同じ<strong>フィルタ</strong>を使用できます。例えば、 アニメーションステージのWFAショートをすべて選択できます。 検索バーに<strong>animation=wfa</strong>と入力します。<strong>Add selection</strong>ボタンで選択を確定します。 Kitsuは<strong>Animation</strong>ステージで<strong>WFA</strong>ステータスを持つショットを選択しますが、Kitsuは自動的に<strong>最新のアップロードバージョン</strong>を読み込みます。</p><p>ショットは画面の上部に表示されます。 変更はすべて 自動的に保存されます。</p><p><img src="'+cp+'" alt="プレイリストページ"></p><h2 id="レビューと検証" tabindex="-1">レビューと検証 <a class="header-anchor" href="#レビューと検証" aria-label="Permalink to “レビューと検証”">​</a></h2><p>プレイリストを作成すると、いくつかのオプションが利用可能になります。</p><p><img src="'+_p+'" alt="プレイリスト全体"></p><ul><li><p>再生または一時停止</p></li><li><p>要素から要素への移動</p></li><li><p>選択した要素の位置を全要素数と比較して表示</p></li><li><p>サウンドのミュートまたはミュート解除</p></li><li><p>速度の変更、2倍速（x2）、通常速度（x1）、半分の速度（x0.50）、4分の1の速度（x0.25</p></li><li><p>1つの要素のループ再生</p></li><li><p>サウンド波形の表示</p></li><li><p>再生中の注釈の表示</p></li><li><p>プレイリスト全体の時間コードに対する要素の時間コード</p></li><li><p>フレーム数</p></li><li><p>プレビュー上でフレーム単位の移動。キーボード上の矢印でも移動できます。</p></li><li><p>比較ツール</p></li><li><p>描画コメントの取り消しとやり直しオプション</p></li><li><p>テキストと描画オプション、選択した項目の削除</p></li><li><p>プレイリストの全要素のタスクタイプを変更</p></li><li><p>コメントセクションを表示</p></li><li><p>プレイリストの要素を隠す</p></li><li><p>LD（低解像度）からHD（高解像度）に切り替え</p></li><li><p>プレイリストを、分割された全要素を含む<strong>Zip</strong>ファイル、<strong>.csv</strong>テキストファイル、または<strong>Build .mp4</strong>としてダウンロードし、ムービー全体を作成（ショットのみ）</p></li><li><p>フルスクリーン</p></li></ul><p>プレイリスト化されたショット/アセットごとに、表示する<strong>タスク</strong>と <strong>バージョン</strong>を選択できます。</p><p><img src="'+dp+'" alt="プレイリストのタスク選択"><img src="'+hp+'" alt="プレイリストのバージョン選択"></p><p>ショットの2つのタスクを並べて再生することもできます。</p><p>[比較] ボタンをクリックします <img src="'+r+'" alt="比較ボタン"> し、2番目のタスクの種類を選択します。</p><p><img src="'+kp+'" alt="プレイリストの並列表示"></p><p>プレイリストの主な目的は、ショットとアセットのレビューをお手伝いすることです。</p><p>プレビューから直接ショットにコメントを追加することができます。</p><p>コメントボタンをクリックします。</p><p><img src="'+bp+'" alt="プレイリストのコメント"></p><p>これで右パネルにアクセスでき、コメントとステータスの全履歴を確認できます。</p><p>ビデオ上の描画コメント（タイムラインの下の赤い点）を見ることができます。</p><p><img src="'+fp+'" alt="プレイリストのコメント"></p><p>ビデオ上に描画したり、文字を入力したりすることができます（ <a href="./../review/">レビューを行う</a>と同じ方法で、<strong>描画</strong>ボタンを使用します！<a href="../img/getting-started/draw.png">描画ボタン</a></p><h2 id="レビュールーム" tabindex="-1">レビュールーム <a class="header-anchor" href="#レビュールーム" aria-label="Permalink to “レビュールーム”">​</a></h2><p>プレイリストの上部に、<strong>「レビュールームに参加」</strong>ボタンがあります。 レビュールームは、すべての参加者を同期します。</p><p>レビュールーム内の全員が、再生と一時停止、ショットとフレームの選択をリアルタイムで確認できます。</p><p>また、レビュールーム内の全員が、同期された描画注釈も確認できます。</p><p><img src="'+jp+'" alt="プレイリストレビュールーム"></p><h2 id="プレビューのバッチアップロード-サムネイルとして" tabindex="-1">プレビューのバッチアップロード（サムネイルとして <a class="header-anchor" href="#プレビューのバッチアップロード-サムネイルとして" aria-label="Permalink to “プレビューのバッチアップロード（サムネイルとして”">​</a></h2><p>グローバルページにある「サムネイルの追加」ボタン <img src="'+up+'" alt="サムネイルの追加ボタン"> を使用して、サムネイルを大量にインポートすることができます。</p><p><img src="'+xp+'" alt="履歴"></p><p>新しいポップアップが開き、サムネイルをリンクするタスクの種類を選択するよう求められます。</p><p><strong>サムネイルの一括インポートでは、画像ファイルと動画ファイルを受け入れます</strong>。</p><p>動画ファイルの場合は、最初のフレームのみがサムネイルとして使用されます。</p><p>サムネイルには、sequence_shotという名前を付ける必要があります。</p>',196)])])}const Tp=t(wp,[["render",Pp]]);export{Kp as __pageData,Tp as default};
